//! # Topological QR Codes — 2D Execution Fingerprints
//!
//! Encodes a 1D Monster Path into a 2D spatial grid (image) that can
//! be reconstructed by the Sovereign Sieve.

use crate::pleromatic_frame::{MonsterPath, SignalToken};
use std::fs::File;
use std::io::{Result, Write};

/// A 2D bit-matrix representing a topological QR code.
pub struct TopologicalQR {
    pub side: usize,
    pub data: Vec<bool>,
}

impl TopologicalQR {
    /// Encodes a MonsterPath into a square 2D grid.
    pub fn encode(path: &MonsterPath) -> Self {
        // Calculate side length (smallest square that fits the path + header + patterns).
        // Patterns take 27 pixels.
        let path_len = path.len();
        let bits_needed = 12 + path_len * 3;
        let mut side = 8;
        while (side * side) < (bits_needed + 27) {
            side += 1;
        }

        let mut data = vec![false; side * side];

        // 1. Add "Position Detection Patterns" (corners).
        for y in 0..3 {
            for x in 0..3 {
                data[y * side + x] = true;
            }
        }
        for y in 0..3 {
            for x in (side - 3)..side {
                data[y * side + x] = true;
            }
        }
        for y in (side - 3)..side {
            for x in 0..3 {
                data[y * side + x] = true;
            }
        }

        // 2. Encode Header (12-bit length).
        let mut path_bits = Vec::new();
        let len_u16 = (path_len as u16) & 0x0fff;
        for i in (0..12).rev() {
            path_bits.push((len_u16 >> i) & 1 == 1);
        }

        // 3. Encode SignalTokens (3-bit each).
        for token in path {
            let val = match token {
                SignalToken::T => 0,
                SignalToken::F { .. } => 1,
                SignalToken::R { .. } => 2,
                SignalToken::L => 3,
                SignalToken::S => 4,
                SignalToken::W { .. } => 5,
                SignalToken::V => 6,
            };
            path_bits.push((val >> 2) & 1 == 1);
            path_bits.push((val >> 1) & 1 == 1);
            path_bits.push(val & 1 == 1);
        }

        let mut data_ptr = 0;
        for bit in path_bits {
            while self::is_pattern_zone(data_ptr % side, data_ptr / side, side) {
                data_ptr += 1;
                if data_ptr >= data.len() {
                    break;
                }
            }
            if data_ptr >= data.len() {
                break;
            }
            data[data_ptr] = bit;
            data_ptr += 1;
        }

        Self { side, data }
    }

    /// Decodes a grid back into a MonsterPath.
    pub fn decode(&self) -> MonsterPath {
        let mut path = Vec::new();
        let mut all_bits = Vec::new();

        for i in 0..self.data.len() {
            if !self::is_pattern_zone(i % self.side, i / self.side, self.side) {
                all_bits.push(self.data[i]);
            }
        }

        if all_bits.len() < 12 {
            return vec![];
        }

        // 1. Decode Length.
        let mut len_u16 = 0u16;
        for i in 0..12 {
            if all_bits[i] {
                len_u16 |= 1 << (11 - i);
            }
        }
        let path_len = len_u16 as usize;

        // 2. Decode Tokens.
        let path_bits = &all_bits[12..];
        for chunk in path_bits.chunks_exact(3).take(path_len) {
            let val = ((chunk[0] as u8) << 2) | ((chunk[1] as u8) << 1) | (chunk[2] as u8);
            let token = match val {
                0 => SignalToken::T,
                1 => SignalToken::F { r: 0 },
                2 => SignalToken::R { r: 0 },
                3 => SignalToken::L,
                4 => SignalToken::S,
                5 => SignalToken::W { m: 0 },
                6 => SignalToken::V,
                _ => SignalToken::V, // Fallback
            };
            path.push(token);
        }

        path
    }

    /// Encodes raw binary data into a square 2D grid.
    pub fn encode_data(payload: &[u8]) -> Self {
        let bit_len = payload.len() * 8;
        let bits_needed = 24 + bit_len; // 24-bit header for length
        let mut side = 8;
        while (side * side) < (bits_needed + 27) {
            side += 1;
        }

        let mut data = vec![false; side * side];

        // 1. Patterns
        for y in 0..3 {
            for x in 0..3 {
                data[y * side + x] = true;
            }
        }
        for y in 0..3 {
            for x in (side - 3)..side {
                data[y * side + x] = true;
            }
        }
        for y in (side - 3)..side {
            for x in 0..3 {
                data[y * side + x] = true;
            }
        }

        // 2. Header (24-bit length)
        let mut all_bits = Vec::new();
        let len_u32 = (payload.len() as u32) & 0x00ffffff;
        for i in (0..24).rev() {
            all_bits.push((len_u32 >> i) & 1 == 1);
        }

        // 3. Data bits
        for &byte in payload {
            for i in (0..8).rev() {
                all_bits.push((byte >> i) & 1 == 1);
            }
        }

        let mut data_ptr = 0;
        for bit in all_bits {
            while self::is_pattern_zone(data_ptr % side, data_ptr / side, side) {
                data_ptr += 1;
                if data_ptr >= data.len() {
                    break;
                }
            }
            if data_ptr >= data.len() {
                break;
            }
            data[data_ptr] = bit;
            data_ptr += 1;
        }

        Self { side, data }
    }

    /// Decodes raw data from the grid.
    pub fn decode_data(&self) -> Vec<u8> {
        let mut all_bits = Vec::new();
        for i in 0..self.data.len() {
            if !self::is_pattern_zone(i % self.side, i / self.side, self.side) {
                all_bits.push(self.data[i]);
            }
        }

        if all_bits.len() < 24 {
            return vec![];
        }

        // 1. Header
        let mut len_u32 = 0u32;
        for i in 0..24 {
            if all_bits[i] {
                len_u32 |= 1 << (23 - i);
            }
        }
        let payload_len = len_u32 as usize;

        // 2. Bytes
        let mut payload = Vec::with_capacity(payload_len);
        let data_bits = &all_bits[24..];
        for chunk in data_bits.chunks_exact(8).take(payload_len) {
            let mut byte = 0u8;
            for i in 0..8 {
                if chunk[i] {
                    byte |= 1 << (7 - i);
                }
            }
            payload.push(byte);
        }

        payload
    }

    /// Saves the grid as a binary PPM image (P3 format).
    pub fn save_as_ppm(&self, path: &str) -> Result<()> {
        let mut f = File::create(path)?;
        write!(f, "P3\n{} {}\n255\n", self.side, self.side)?;
        for bit in &self.data {
            if *bit {
                write!(f, "0 255 0 ")?;
            } else {
                write!(f, "0 0 0 ")?;
            }
        }
        Ok(())
    }

    /// Saves the grid as a PNG image.
    #[cfg(not(target_arch = "wasm32"))]
    pub fn save_as_png(&self, path: &str) -> std::result::Result<(), String> {
        use image::{Rgb, RgbImage};
        let mut img = RgbImage::new(self.side as u32, self.side as u32);
        for (i, bit) in self.data.iter().enumerate() {
            let x = (i % self.side) as u32;
            let y = (i / self.side) as u32;
            let pixel = if *bit {
                Rgb([0, 255, 0])
            } else {
                Rgb([0, 0, 0])
            };
            img.put_pixel(x, y, pixel);
        }
        img.save(path).map_err(|e| e.to_string())
    }

    /// Saves the grid as a WebP image.
    #[cfg(not(target_arch = "wasm32"))]
    pub fn save_as_webp(&self, path: &str) -> std::result::Result<(), String> {
        use image::{Rgb, RgbImage};
        let mut img = RgbImage::new(self.side as u32, self.side as u32);
        for (i, bit) in self.data.iter().enumerate() {
            let x = (i % self.side) as u32;
            let y = (i / self.side) as u32;
            let pixel = if *bit {
                Rgb([0, 255, 0])
            } else {
                Rgb([0, 0, 0])
            };
            img.put_pixel(x, y, pixel);
        }
        img.save(path).map_err(|e| e.to_string())
    }

    /// Exports a sequence of rotating frames as PNGs for video assembly.
    #[cfg(not(target_arch = "wasm32"))]
    pub fn export_rotation_sequence(
        &self,
        dir: &str,
        frames: usize,
    ) -> std::result::Result<(), String> {
        use std::fs;
        fs::create_dir_all(dir).map_err(|e| e.to_string())?;
        for i in 0..frames {
            let path = format!("{}/frame_{:04}.png", dir, i);
            self.save_as_png(&path)?;
        }
        Ok(())
    }
}

fn is_pattern_zone(x: usize, y: usize, side: usize) -> bool {
    // Corner patterns (3x3)
    (x < 3 && y < 3) || (x >= side - 3 && y < 3) || (x < 3 && y >= side - 3)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::pleromatic_frame::SignalToken;

    #[test]
    fn test_qr_roundtrip() {
        let path = vec![
            SignalToken::T,
            SignalToken::S,
            SignalToken::T,
            SignalToken::V,
            SignalToken::V,
        ];
        let qr = TopologicalQR::encode(&path);
        let decoded = qr.decode();
        assert_eq!(decoded.len(), path.len());
        assert_eq!(decoded[0], SignalToken::T);
        assert_eq!(decoded[1], SignalToken::S);
    }

    #[test]
    fn test_data_qr_roundtrip() {
        let payload = b"HELLO:MONSTER";
        let qr = TopologicalQR::encode_data(payload);
        let decoded = qr.decode_data();
        assert_eq!(payload, &decoded[..]);
    }
}
